const express = require('express');
const sgMail = require('@sendgrid/mail');

sgMail.setApiKey('SG.test_key_abc123');

const app = express();
app.use(express.json());

async function sendEmailNotification({ to, subject, text, html, from = 'devops-internal@example.com' }) {
  const msg = {
    to,
    from,
    subject,
    text: text || '',
    html: html || undefined,
  };

  return sgMail.send(msg);
}

app.post('/send-notification', async (req, res) => {
  try {
    const { to, subject, text, html, from } = req.body;

    if (!to || !subject || (!text && !html)) {
      return res.status(400).json({
        error: 'Required fields: to, subject, and either text or html',
      });
    }

    const result = await sendEmailNotification({ to, subject, text, html, from });

    res.status(200).json({
      success: true,
      message: 'Email sent successfully',
      result,
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message,
      details: error.response && error.response.body ? error.response.body : undefined,
    });
  }
});

module.exports = { app, sendEmailNotification };

if (require.main === module) {
  const port = process.env.PORT || 3000;
  app.listen(port, () => {
    console.log(`Email notification service running on port ${port}`);
  });
}